-- 002_seed_sku_master.sql
-- Seeds sku_master from sku_master.csv (161 SKUs)
--
-- Mapping:
--   CSV ASIN        -> asin
--   CSV SKU         -> sku (PRIMARY KEY)
--   CSV Title       -> name
--   CSV FNSKU       -> fnsku
--   CSV Category    -> sub_category (product line, NOT ABC category)
--   CSV Sub-Category -> sub_category detail (stored together as sub_category)
--   CSV COGS        -> cogs
--
-- category (ABC classification) is set to NULL — must be set after threshold analysis
-- units_per_box defaults to 1 — operator must update
-- moq and lead_time_days are NULL — operator must set

ON CONFLICT (sku) DO NOTHING;
